#
# Dataset builder for forward-sampling probabilistic reasoning data.
#
# Data is generated by forward_sampling/generate_finetuning_dataset.py and
# written to torchtune/data/forward_sampling_dataset_{train,val,test}.json.
# Each record has the same {input, output, bins, metadata} format as the
# posterior-sampling dataset, so the same ProbabilisticReasoningDataset class
# and training recipe work without modification.
#
from torchtune.modules.tokenizers import ModelTokenizer
import sys
import os

# Add parent directory to path to import ProbabilisticReasoningDataset
sys.path.insert(0, os.path.join(os.path.dirname(__file__), '../..'))
from probabilistic_reasoning_utils import ProbabilisticReasoningDataset


def data(tokenizer: ModelTokenizer, packed: bool = False, max_seq_length: int = 2048,
         bracket_format: bool = False):
    """
    Dataset builder for forward-sampling probabilistic reasoning task.

    Uses ProbabilisticReasoningDataset which returns:
    - tokens: Tokenized input + output
    - labels: Labels with input masked (-100)
    - ground_truth_bins: Point-estimate distributions [num_queries, 101]

    Args:
        tokenizer: Model tokenizer
        packed: Whether to pack sequences (not implemented, returns None)
        max_seq_length: Maximum sequence length (default: 2048)
        bracket_format: If True, swap the instruction prefix for BRACKET_INSTRUCTION
            and wrap each bare-integer output as <N>. Required to keep input prompt
            and answer parsing on the bracket convention used elsewhere.

    Returns:
        [ds_list_train, ds_list_dev, ds_list_test] where each is a list with one dataset
    """

    ds_list_train, ds_list_dev, ds_list_test = [], [], []

    ds_train = ProbabilisticReasoningDataset(
        data_path='data/forward_sampling_dataset_train.json',
        tokenizer=tokenizer,
        max_seq_length=max_seq_length,
        bracket_format=bracket_format,
    )
    ds_list_train.append(ds_train)

    ds_dev = ProbabilisticReasoningDataset(
        data_path='data/forward_sampling_dataset_val.json',
        tokenizer=tokenizer,
        max_seq_length=max_seq_length,
        bracket_format=bracket_format,
    )
    ds_list_dev.append(ds_dev)

    ds_test = ProbabilisticReasoningDataset(
        data_path='data/forward_sampling_dataset_test.json',
        tokenizer=tokenizer,
        max_seq_length=max_seq_length,
        bracket_format=bracket_format,
    )
    ds_list_test.append(ds_test)

    ds = [ds_list_train, ds_list_dev, ds_list_test]

    if packed:
        return None  # Packed mode not implemented
    else:
        return ds
